insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-postpartum-care', '産後ケア事業（宿泊型・通所型・訪問型）', '千代田区が母子保健法に基づき実施する産後ケア事業。出産後のお母さんと赤ちゃんを対象に、助産師等による心身のケア・授乳相談・育児相談などを、施設に宿泊する「宿泊型」、施設に日帰りで通う「通所型」、自宅で受ける「訪問型」の3つの形で提供します。利用日時点で千代田区に住民票がある方が対象となる可能性があります。利用回数・利用料・自己負担・減免・利用施設などの条件は公式ページおよび区のチラシで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんなどから体と心のケアや授乳・育児の相談を受けられる千代田区の制度です。施設に泊まる「宿泊型」、日帰りで通う「通所型」、自宅に来てもらう「訪問型」から選べます。千代田区に住んでいる方が対象になる可能性があり、料金や回数などは区のチラシで確認してください。', 'service', '利用日時点で千代田区に住民票の登録があるお母さんとそのお子さんが対象となる可能性があります（流産・死産された方も対象となる場合あり。医療行為が必要な場合は利用できないことがあります）。詳しい対象要件は公式ページで確認してください。', '利用料・自己負担額は産後ケア事業のチラシ（区公式PDF）に記載され、区独自に設定・変更されます。公式案内によると2,500円減免クーポンが産婦1人につき5枚配付され、住民税非課税世帯等は自己負担が免除されるとされています。利用回数は類型ごとに異なり（公式では宿泊型6泊7日まで・通所型5回まで・訪問型5回まで等とされ、令和8年3月31日までに出産された方など経過措置で回数が異なる場合があります）、具体的な料金・回数は公式の最新チラシで確認してください。', '公式案内では妊娠28週以降に事前申請を行うとされています。利用予約・キャンセルの期限など詳細は公式ページおよび利用施設で確認してください。', '公式案内によると、妊娠28週以降にmila-e（ミラe）申請フォームから事前申請を行ったうえで、利用を希望する実施施設に直接予約する流れです。本人確認書類（運転免許証・マイナンバーカード等）が必要とされ、非課税世帯等で自己負担免除を受ける場合は世帯全員の住民税非課税証明書または生活保護受給証明書が必要とされています。最新の手続き・必要書類は公式ページで確認してください。', '本人確認書類（運転免許証・マイナンバーカード等）。非課税世帯等で自己負担免除を希望する場合は世帯全員の住民税非課税証明書または生活保護受給証明書が必要とされています。最新の必要書類は公式ページで確認してください。', TRUE, '千代田保健所 保健サービス課 保健相談係（事業内容に関する問い合わせ）', '03-5211-8175', NULL, 'https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/sango.html', '産後ケア事業（宿泊型、通所型、訪問型） - 千代田区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本内容は確認日時点の千代田区公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび区の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
