insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot postpartum-care import', '{"slug":"tokyo-chiyoda-postpartum-care","status":"published","title":"産後ケア事業（宿泊型・通所型・訪問型）","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/sango.html","topic":"postpartum-care"}'::jsonb, 'pilot:tokyo-chiyoda-postpartum-care:dG9reW8tY2hpeW9kYS1wb3N0cGFydHVtLWNhcmV8' from public.support_programs sp where sp.slug='tokyo-chiyoda-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-postpartum-care', '中央区 産後ケア事業', '東京都中央区が実施する産後ケア事業です。出産後の母子を対象に、助産師等によるお母さんの体調・心のケアや授乳・育児の相談・支援を、宿泊型・日帰り（デイ）型・訪問（アウトリーチ）型の3つの形で提供します。対象月齢・利用回数・利用料・利用できる施設は区の定めにより異なるため、利用前に中央区公式ページおよび施設一覧で必ず確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんから体や心のケア・授乳や育児の相談を受けられる中央区の事業です。施設に泊まる「宿泊型」、日中だけ通う「日帰り型」、自宅に来てもらう「訪問型」があります。料金や使える回数・施設は決まりがあるので、区の公式ページで確認してから申し込みます。', 'service', '中央区に住民登録がある出産後のお母さんとお子さんが対象となる可能性があります。受入対象となる月齢（おおむね産後一定期間）は利用施設により異なるため、公式ページで確認してください。', '利用料は施設や世帯の課税状況により異なります（住民税非課税世帯は減額、生活保護世帯は無料の取扱いあり）。具体的な金額は中央区公式ページおよび「産後ケア事業施設一覧」で確認してください。', '利用希望日のおおむね14日前まで（公式ページで確認してください）', '利用希望日のおおむね14日前までに、申請書・母子健康手帳・本人確認書類等を添えて申請します。申請方法は電子申請フォーム、窓口、郵送のいずれかが案内されています。申請・相談先は中央区保健所（明石町）および日本橋・月島・晴海の各保健センターです。具体的な締切・提出先・必要書類は公式ページで確認してください。', '申請書、母子健康手帳、本人確認書類（運転免許証・健康保険証・マイナンバーカード等）、該当する場合は住民税非課税を証する書類または生活保護受給を証する書類。詳細は公式ページで確認してください。', TRUE, '中央区保健所', '03-3541-5930', 'https://www.city.chuo.lg.jp/a0031/kosodate/shussan/shussanshien/user_fkensu_time_20170323.html', 'https://www.city.chuo.lg.jp/a0031/kosodate/shussan/shussanshien/user_fkensu_time_20170323.html', '中央区ホームページ／産後ケア事業', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText', 'targetPeople']::text[], '本ページは中央区公式情報をもとにした概要です。対象・利用料・回数・施設は変更される場合があるため、最新の正確な内容は必ず中央区公式ページおよび施設一覧でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
