insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot postpartum-care import', '{"slug":"tokyo-chuo-postpartum-care","status":"published","title":"中央区 産後ケア事業","officialUrl":"https://www.city.chuo.lg.jp/a0031/kosodate/shussan/shussanshien/user_fkensu_time_20170323.html","topic":"postpartum-care"}'::jsonb, 'pilot:tokyo-chuo-postpartum-care:dG9reW8tY2h1by1wb3N0cGFydHVtLWNhcmV85Lit' from public.support_programs sp where sp.slug='tokyo-chuo-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-postpartum-care', '港区 産後母子ケア事業（宿泊型・デイサービス・乳房ケア）', '港区が母子保健法に基づき実施する産後ケア事業。出産後の母子の心身のケアや授乳・育児の相談を、宿泊型（ショートステイ）・通所型（デイサービス／乳房ケア外来）・訪問型（乳房ケア）の形で、区が契約する医療機関・助産師等で受けられる可能性があります。対象月齢・利用料・回数・利用施設は事業区分や施設ごとに異なるため、必ず港区公式ページで確認してください。', '赤ちゃんを産んだあとのお母さんと赤ちゃんが、体や心のケア・授乳や育児の相談を受けられる港区の事業です。泊まって受ける宿泊型、日帰りで受けるデイサービス、おっぱいのケア（外来・自宅訪問）があります。利用には事前の登録申請が必要で、対象となる赤ちゃんの月齢や料金・回数は施設によって異なります。', 'service', '港区に住民登録のある母子が対象となる可能性があります。対象となる赤ちゃんの月齢は事業区分・施設により異なり（宿泊型はおおむね産後10週未満〜産後5か月未満の範囲で施設ごとに設定、デイサービス・乳房ケアも施設により異なる）、詳細は公式で確認が必要です。', '宿泊型は課税世帯で1泊2日あたり1,000〜10,000円の範囲で施設ごとに設定（非課税・生活保護世帯は免除）。デイサービス・乳房ケアは課税世帯で各施設利用料の1割（上限2,000円）、非課税世帯は自己負担なしと公式で案内（確認日時点）。金額は施設・世帯区分で異なるため公式で要確認。', 'おおむね妊娠8か月〜利用日の14日前まで（公式で要確認）', '事前の登録申請が必要。申請期間はおおむね妊娠8か月〜利用日の14日前まで。みなと保健所窓口への提出・郵送・電子申請（ロゴフォーム）のいずれかで申請できると公式で案内（宿泊型とデイサービス・乳房ケアで申請書が分かれる）。最新の手続きは公式ページで確認してください。', '利用登録申請書。非課税世帯は非課税証明書（世帯全員分）等が必要。必要書類の詳細は港区公式ページ・申請窓口で確認してください。', TRUE, 'みなと保健所 健康推進課 地域保健係', '03-6400-0084', 'https://www.city.minato.tokyo.jp/chiikihoken/kodomo/boshi-shortstay.html', 'https://www.city.minato.tokyo.jp/chiikihoken/kodomo/boshi-shortstay.html', '産後母子ケア宿泊型ショートステイ事業（港区ホームページ）', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は港区公式ページ(確認日2026-06-24)に基づく概要です。対象月齢・利用料・自己負担・利用回数・利用施設は事業区分や施設ごとに異なり変更されることがあります。利用可否や最新の条件は必ず港区公式ページおよびみなと保健所でご確認ください。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
