insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot postpartum-care import', '{"slug":"tokyo-minato-postpartum-care","status":"published","title":"港区 産後母子ケア事業（宿泊型・デイサービス・乳房ケア）","officialUrl":"https://www.city.minato.tokyo.jp/chiikihoken/kodomo/boshi-shortstay.html","topic":"postpartum-care"}'::jsonb, 'pilot:tokyo-minato-postpartum-care:dG9reW8tbWluYXRvLXBvc3RwYXJ0dW0tY2FyZXzm' from public.support_programs sp where sp.slug='tokyo-minato-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-postpartum-care', '新宿区 産後ケア事業', '新宿区が母子保健法に基づき実施する産後ケア事業。産後の母子の心身のケアや育児サポートを目的に、支援施設に宿泊するショートステイ型、日帰りで通うデイサービス型、助産師が自宅を訪問するアウトリーチ型の3つの方法で支援を行う。対象・利用料・回数・対象月齢・利用施設は公式ページや施設ごとに異なるため、利用前に新宿区公式で確認する必要がある。', '出産後のお母さんと赤ちゃんの心と体をケアするため、新宿区が行っている支援です。施設に泊まる宿泊型、日帰りで通う通所型、助産師さんが自宅に来てくれる訪問型の3つから選べます。授乳や育児の相談、お母さんの休養、赤ちゃんの体重・健康チェックなどをサポートしてもらえます。対象や料金、利用できる回数・施設は条件によって変わるので、利用前に新宿区の公式ページで確認してください。', 'service', '母親と赤ちゃんの両方が新宿区に住民登録があり、産後ケアを必要とし、医療行為・入院加療が不要な方が対象となる可能性がある。対象月齢は施設により「産後2か月未満」から「産後7か月未満」まで異なるため、詳細は公式で確認が必要。', 'アウトリーチ型（訪問）は1回1,000円（非課税世帯は減額、生活保護受給世帯は免除）。ショートステイ型（宿泊）・デイサービス型（通所）の追加料金の有無は施設により異なるため施設に確認する必要がある。', '妊娠7か月（24週）以降、利用予定日の2週間前まで（公式で確認）。', '妊娠7か月（24週）以降、利用予定日の2週間前までに、電子申請・郵送・担当保健センターの窓口のいずれかで「新宿区産後ケア事業利用登録申請書」を提出する。詳細・最新情報は公式ページで確認すること。', '新宿区産後ケア事業利用登録申請書。利用当日は「利用登録決定通知書」と「母子健康手帳」が必要（公式で確認）。', TRUE, '新宿区健康部健康づくり課 母子保健担当', '03-5273-3047', NULL, 'https://www.city.shinjuku.lg.jp/fukushi/postpartum_care.html', '新宿区産後ケア事業のご案内', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は確認日（2026-06-24）時点で新宿区公式ページに掲載されていた内容に基づく概要です。対象者・利用料・自己負担・利用回数・対象月齢・利用施設などは変更される場合があり、施設や世帯状況によっても異なります。最新かつ正確な内容は必ず新宿区公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
