insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot postpartum-care import', '{"slug":"tokyo-shinjuku-postpartum-care","status":"published","title":"新宿区 産後ケア事業","officialUrl":"https://www.city.shinjuku.lg.jp/fukushi/postpartum_care.html","topic":"postpartum-care"}'::jsonb, 'pilot:tokyo-shinjuku-postpartum-care:dG9reW8tc2hpbmp1a3UtcG9zdHBhcnR1bS1jYXJl' from public.support_programs sp where sp.slug='tokyo-shinjuku-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-postpartum-care', '文京区 産後ケア事業（宿泊型・デイサービス型・訪問型）', '文京区が母子保健法に基づき実施する産後ケア事業です。出産後の母子の心身のケアや育児相談を、宿泊型ショートステイ、デイサービス型サロン、助産師による訪問型（出張相談）の3類型で提供します。助産師らが母体の健康観察・乳房ケア、赤ちゃんの健康観察、育児サポート・相談などを行います。文京区に住民登録がある出産後の母子が対象となる可能性があります。利用料・自己負担額・利用回数・対象月齢・利用施設は類型や施設、世帯状況により異なるため、必ず公式ページで最新の条件をご確認ください。', '出産のあと、お母さんと赤ちゃんが助産師などのケアや育児相談を受けられる文京区の事業です。泊まって受ける「宿泊型」、日帰りの「デイサービス型」、自宅に来てもらう「訪問型」があります。文京区に住民登録のある産後の母子が対象になる可能性があります。利用にはお金がかかりますが、収入によって安くなる仕組みもあります。申し込みはオンライン（mila-e）ででき、利用したい日の3営業日前までに手続きが必要です。料金や回数、利用できる施設は種類によってちがうので、公式ページで確認してください。', 'service', '公式ページによると、文京区に住民登録がある出産後のお母さんと赤ちゃんが対象となる可能性があります。訪問型（助産師出張相談）は産後1年未満で、赤ちゃんのお世話や産後の回復に不安がある方、家族のサポートが十分でない方などが対象とされています。宿泊型・デイサービス型は対象となる月齢が施設・類型により異なるため、公式ページでの確認が必要です。', 'サービス提供（現物給付）であり、利用には自己負担があります。公式ページの記載では、宿泊型は1泊2日でおおむね3,600～7,200円程度（その後1日ごとに加算)、デイサービス型は1日3,000円程度、訪問型は1回3,000円程度とされ、生活保護・非課税など減免対象世帯には減免の仕組みがあります。金額は施設・類型・世帯状況により異なるため、正確な額は公式ページで確認が必要です。', '公式ページによると、利用希望日の3営業日前までにクーポン申請・受取が必要です。訪問型は妊娠8か月（28週）以降から申請可能とされています。', 'オンライン申請（mila-e申請システム）に対応しています。メールアドレスでアカウント登録のうえ、クーポンを申請・受け取って利用します。利用希望日の3営業日前までにクーポン申請・受取が必要とされています。詳細・最新の手順は公式ページでご確認ください。', '公式ページの記載では、課税世帯は原則不要。生活保護・非課税世帯は減免のための証明書（写しの添付または原本提出）が必要とされています。最新の必要書類は公式で確認が必要です。', TRUE, '文京保健所保健サービスセンター', '03-5803-1805', 'https://www.city.bunkyo.lg.jp/b029/p001557.html', 'https://www.city.bunkyo.lg.jp/b029/p001557.html', '宿泊型ショートステイ・デイサービス型サロン（個別） | 文京区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本要約は文京区公式ページ（確認日2026-06-24）に基づく参考情報です。利用料・自己負担額・利用回数・対象月齢・利用施設などの条件は変更されることがあり、施設や世帯状況によっても異なります。最新かつ正確な内容は必ず公式ページおよび文京保健所保健サービスセンターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
