insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-postpartum-care', '台東区 産後ケア事業（宿泊型・日帰り型・外来型/訪問型乳房ケア）', '台東区が母子保健法に基づき実施する産後ケア事業。出産後のママと赤ちゃんが、助産師などのアドバイスを受けながら育児方法を学んだり、育児の不安を軽減できる場として提供される。実施施設に宿泊する「宿泊型」、日中滞在する「日帰り型」のほか、助産師による授乳・育児相談を受けられる「外来型乳房ケア」「訪問型乳房ケア」がある。対象・利用料・自己負担額・利用回数の上限・実施施設などは公式ページで確認が必要。', '台東区が行っている産後ケアです。出産後のお母さんと赤ちゃんが、助産師などに相談しながら休んだり、授乳や育児のサポートを受けられます。施設に泊まる「宿泊型」、日中だけ過ごす「日帰り型」、授乳などの相談ができる「外来型・訪問型の乳房ケア」があります。利用料の自己負担や対象になる時期、利用できる回数などは台東区の公式ページでご確認ください。', 'service', '出産後一定期間内（産後1年未満）のママと赤ちゃんで、台東区に住民登録があり産後ケアを必要とする方が対象。詳細な要件は公式で確認。', '施設の設定金額から区の負担額を差し引いた額が自己負担となる方式。宿泊型・日帰り型・外来型/訪問型乳房ケアで負担額や減免支援の内容が異なり、年度（令和8年度等）により設定金額が更新されるため、具体的な自己負担額は公式ページで確認が必要。', '利用申込は原則、出産後～利用前日（土日祝・年末年始を除く）の午前10時まで（公式で確認）。', '事前申請（妊娠28週以降、mila-e〔ミライー〕からの申請）を行ったうえで、利用日の予約を浅草保健相談センター 母子健康包括支援担当へ電話等で申し込む。利用申込は原則、出産後～利用前日（土日祝・年末年始を除く）の午前10時まで。詳細・申込方法は公式ページで確認。', '利用当日は母子健康手帳やスマートフォン等の端末、利用に必要な持ち物の持参が案内されている。必要書類の詳細は公式ページで確認が必要。', TRUE, '台東区 浅草保健相談センター 母子健康包括支援担当', '03-3844-8177', 'https://www.city.taito.lg.jp/kosodatekyouiku/kosodate/mokutei/kenkou_iryou/shussan/sangocare.html', 'https://www.city.taito.lg.jp/kosodatekyouiku/kosodate/mokutei/kenkou_iryou/shussan/sangocare.html', '産後ケア（宿泊型・日帰り型）　台東区ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象・利用料・自己負担額・利用回数の上限・対象月齢・実施施設は年度や施設により異なり、本ページ作成時点の情報と公式の最新情報が異なる場合があります。必ず台東区公式ページおよび浅草保健相談センターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
