insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-postpartum-care', '墨田区 産後ケア事業', '墨田区が母子保健法に基づき実施する産後ケア事業。産後の母体の回復支援、授乳指導・乳房ケア、育児相談、保健指導などを、宿泊型・日帰り型・外来型・訪問型の4つのタイプで提供する。墨田区に住民登録のある産後1年未満の母子が対象となる可能性がある（宿泊型・日帰り型は原則産後4か月未満）。利用には事前申請が必要で、電子申請（Logoフォーム）にも対応している。', '墨田区にお住まいで出産後まもないお母さんと赤ちゃんが、助産師などから授乳や乳房ケア、育児の相談、母体の回復のサポートを受けられる区の事業です。施設に泊まる宿泊型、日中だけ通う日帰り型、医療機関などに通う外来型、自宅に来てもらう訪問型の4つから選べます。利用には事前の申し込みが必要で、インターネット（電子申請）でも申し込めます。利用料や利用できる回数はタイプや世帯の状況によって異なるため、詳しくは墨田区の公式ページで確認してください。', 'service', '墨田区に住民登録のある産後1年未満の母子が対象となる可能性がある。宿泊型・日帰り型は原則産後4か月未満が対象とされる。詳しい対象要件は墨田区公式ページで確認のこと。', '宿泊型・日帰り型・外来型・訪問型の各タイプごとに利用回数の上限と利用者負担額が設定されている。住民税非課税世帯および生活保護世帯等は利用者負担額が免除される場合がある。具体的な負担額・回数は区独自に定められ変動の可能性があるため、墨田区公式ページで確認すること。', '通年で受付。利用には事前の申請が必要で、産後の準備として妊娠中の申請が案内されている。具体的な期限は墨田区公式ページで確認のこと。', '利用には事前の申請が必要。すみだ保健子育て総合センター健康推進課（産後ケア担当、電話03-3622-9139または03-3622-9152）への申請のほか、墨田区産後ケア事業利用電子申請（Logoフォーム）によるオンライン申請にも対応している。申請後1週間程度で承認通知が郵送される。妊娠中の事前申請が案内されている。最新の申請方法・窓口は墨田区公式ページで確認すること。', '利用当日は利用承認通知書・親子健康手帳（母子手帳）・健康保険証等が必要とされる。非課税世帯は住民税非課税証明書、生活保護世帯は保護証明書等が求められる場合がある。最新の必要書類は墨田区公式ページで確認すること。', TRUE, '墨田区 すみだ保健子育て総合センター 健康推進課（産後ケア担当）', '03-3622-9139', 'https://www.city.sumida.lg.jp/kenko_fukushi/kenko/oyako_kenko/sangoriyou/sangocarenyubocare.html', 'https://www.city.sumida.lg.jp/kenko_fukushi/kenko/oyako_kenko/sangoriyou/sangocarenyubocare.html', '産後のお母さんを応援！産後ケア事業 - 墨田区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は確認日時点の墨田区公式ページに基づく概要です。対象月齢・利用回数・利用料・自己負担額・利用施設は変更される場合があります。実際の利用可否や条件は必ず墨田区公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
