insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'koto-postpartum-care', '産後ケア事業', '江東区が母子保健法に基づき実施する産後ケア事業。宿泊型・日帰り型・訪問型・スポット型があり、出産後の母子の心身のケアや育児サポートを受けられます。', '江東区にお住まいで出産された方が、助産師などから心と体のケアや育児のサポートを受けられる制度です。施設に泊まる「宿泊型」、日中だけ利用する「日帰り型」、自宅に来てもらう「訪問型」、必要なときに利用する「スポット型」があります。申し込みは妊娠届を出すときの『ゆりかご面接』で行います。料金や利用できる回数は種類や施設によって違うので、公式ページで確認してください。', 'service', '江東区に住民登録のある産後の母子。宿泊型・日帰り型は産後4か月未満、訪問型・スポット型は産後1年未満が対象（対象月齢・受入条件は類型や施設により異なるため公式で確認）。', '令和8年4月1日改定の利用者負担金。宿泊型は1泊2日9,800円〜5泊6日29,400円（多胎児は1人1日2,400円加算）。日帰り型・訪問型・スポット型の料金や減免・利用回数の上限は類型・施設により異なるため公式で確認してください。住民税非課税・生活保護世帯は減免があります。', NULL, '妊娠届提出時の「ゆりかご面接」で産後ケア事業に申し込み、承認番号の発行を受けます。利用時は希望施設へ電話または施設ホームページ等で予約します。詳細は保健相談所・保健予防課保健係へお問い合わせのうえ公式ページでご確認ください。', NULL, FALSE, '江東区 健康部（保健所）保健予防課 保健係', '03-3647-5906', NULL, 'https://www.city.koto.lg.jp/260501/kodomo/ninshinshussan/kenko/99710.html', '産後ケア事業｜江東区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '利用料・対象月齢・利用回数・実施施設は類型や施設により異なり、改定される場合があります。最新の正確な情報は必ず江東区公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
