insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-postpartum-care', '産後ケア事業（品川区）', '品川区が母子保健法に基づき実施する産後ケア事業。出産後の母親の心身のケアや育児サポートを、宿泊型・日帰り型（個別／集団）・訪問型で提供し、育児不安の軽減を図ります。種別ごとに対象月齢・利用料・利用回数・利用施設が異なるため、詳細は公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが心と体を休め、授乳や育児の相談ができる品川区のサービスです。施設に泊まる「宿泊型」、日中だけ利用する「日帰り型」、助産師などが自宅に来る「訪問型」があります。種類によって、利用できる時期・回数・料金・施設が違います。', 'service', '品川区に住民登録がある産後の母子が対象となる可能性があります。種別により対象月齢が異なり、宿泊型は産後5カ月未満、訪問型・日帰り型（個別）は産後1年未満などとされます。最終的な対象可否は公式ページや保健センターでご確認ください。', '宿泊型は自己負担あり（例：1泊2日で3,700円～7,400円程度、6泊7日で17,550円～25,900円程度。施設により異なる。非課税世帯は半額、生活保護世帯は免除）。訪問型・日帰り型は利用者負担なし（助成回数を超えた分は自費）。金額・回数は変更される場合があるため公式で確認してください。', '原則として利用日の2週間前まで（公式で確認）', '妊娠期面談時に申請するか、品川区電子申請サービスから申請します。原則として利用日の2週間前までに申請を完了する必要があります（種別により予約・受付窓口が異なります）。詳細は公式ページで確認してください。', '申請方法・必要書類は種別および妊娠期面談の有無により異なるため、公式ページおよび各保健センターで確認してください。減免を受ける場合は最新年度の非課税証明書または生活保護受給証明書が必要です。', TRUE, '品川保健センター／大井保健センター／荏原保健センター', '品川保健センター 03-3474-2225／大井保健センター 03-3772-2666／荏原保健センター 03-3788-7013', 'https://www.city.shinagawa.tokyo.jp/PC/kodomo/kodomo-ninnshinn/kodomo-ninnshinn-umaretara/20240328204508.html', 'https://www.city.shinagawa.tokyo.jp/PC/kodomo/kodomo-ninnshinn/kodomo-ninnshinn-umaretara/20240328204508.html', '産後ケア事業 宿泊型｜品川区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '対象・利用料・利用回数・対象月齢・利用施設は品川区が定めるもので変更される場合があります。利用にあたっては必ず品川区公式ページおよび保健センターで最新情報を確認してください。本サービスは申請・要件審査を要し、利用が保証されるものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
