insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-postpartum-care', '目黒区 産後ケア事業', '目黒区が母子保健法に基づき実施する産後ケア事業です。出産後の母子の心身のケアや授乳・育児の相談を、宿泊型・日帰り（通所）型・訪問型・通所「集団」型の形態で受けられる可能性があります。対象月齢の上限・利用料・自己負担・利用回数・利用できる施設は形態や施設により異なるため、最新の内容は目黒区公式サイトで確認してください。', '出産のあと、体調や授乳・育児に不安があるときに、助産師などから赤ちゃんのケアや授乳・育児の相談を受けられる目黒区の事業です。宿泊して受ける型、日帰りで受ける型、自宅に来てもらう訪問型などがあります。対象となる月齢や料金、利用できる回数・施設は型ごとに違うので、公式ページで確認してください。', 'service', '目黒区に住民登録がある産後の母子で、産後の回復や体調・授乳・育児に不安がある、または家族などの支援が得にくい方が対象となる可能性があります（対象月齢の上限は形態・施設により異なります。詳細は公式で確認してください）。', '助産師等による赤ちゃんのケア（健康・体重チェック等）、授乳・調乳・沐浴・栄養指導、育児相談などのサービス。利用料・自己負担は形態や施設により異なり、住民税非課税世帯・生活保護世帯は免除・無料となる場合があります（公式で確認）。', '形態により申請開始時期等が異なります（宿泊型は妊娠8か月（妊娠28週）から申請可能との公式案内）。詳細・最新の取扱いは公式で確認してください。', '公式案内では専用フォーム等から申請し、利用登録の承認後に施設へ予約する形態があります（宿泊型は妊娠8か月（28週）から申請可能との案内）。申請時期・方法は形態により異なるため、目黒区公式ページおよび担当課で確認してください。', '必要書類は形態・施設により異なります。目黒区公式ページおよび担当課で確認してください。', TRUE, '目黒区 地域保健課 保健相談係', '03-5722-9383', 'https://www.city.meguro.tokyo.jp/kosodatekyouiku/ninshin/kenkoukanri/sangocare/index.html', 'https://www.city.meguro.tokyo.jp/kosodatekyouiku/ninshin/kenkoukanri/sangocare/index.html', '産後ケア事業 | 目黒区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は目黒区公式サイト（確認日2026-06-24）に基づく概要です。対象・利用料・回数・対象月齢・利用施設・申請方法は変更される場合があり、形態や施設により異なります。最新かつ正確な内容は必ず目黒区公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
