insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-postpartum-care', '大田区産後ケア事業', '大田区が母子保健法に基づき委託実施する産後ケア事業です。出産後の母親の身体的回復、授乳指導・乳房ケア、育児相談などを支援します。ケアの種類は訪問型・外来型・日帰り型・宿泊型・グループケア型の5種類があり、利用日現在大田区に住民登録している母子が対象となる可能性があります。利用料や自己負担額、対象月齢、利用回数、利用施設は種類ごとに異なるため、詳細は公式ページでご確認ください。', '出産後のお母さんと赤ちゃんが、助産師などから体のケアや授乳・育児の相談を受けられる大田区の支援です。施設に泊まる宿泊型、日帰り型、自宅に来てもらう訪問型などがあります。', 'service', '利用日現在、大田区に住民登録している母子が対象となる可能性があります。宿泊型・日帰り型・グループケア型は産後5か月未満、訪問型・外来型は産後1年未満が対象とされていますが、対象月齢・要件は種類により異なるため公式ページでご確認ください。', '利用料・自己負担額は産後ケアの種類（訪問型・外来型・日帰り型・宿泊型・グループケア型）や利用施設ごとに異なります。グループケア型は利用者負担金なし、生活保護受給者は全額免除とされています。具体的な金額は公式ページでご確認ください。', '利用券冊子は出産後一定期間（おおむね産後1年）有効とされる可能性があります。詳細は公式ページでご確認ください。', '事前の申請手続きは原則不要で、妊婦面接の際に交付される利用券冊子が必要となる可能性があります。予約は各施設へ直接連絡、グループケア型は助産師会の予約システムから申込む形が案内されています。詳細・最新の手続きは公式ページでご確認ください。', '妊婦面接時に交付される利用券冊子が必要となる可能性があります。生活保護受給者など利用料免除を受ける場合は所定の証明が必要となる場合があります。詳細は公式ページでご確認ください。', FALSE, '大田区 健康づくり課', '03-5744-1661', 'https://www.city.ota.tokyo.jp/seikatsu/kodomo/shussan/sango-care.html', 'https://www.city.ota.tokyo.jp/seikatsu/kodomo/shussan/sango-care.html', '大田区ホームページ：大田区産後ケア事業', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は公式ページをもとにした概要です。対象・利用料・回数・施設などは変更される場合があるため、利用前に必ず大田区公式ページおよび健康づくり課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
