insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'setagaya'), 'tokyo-setagaya-postpartum-care', '世田谷区 産後ケア事業', '世田谷区が母子保健法に基づき実施する産後ケア事業。出産後のお母さんと赤ちゃんの生活リズムづくりをサポートし、授乳方法や育児について助産師に相談できます。ショートステイ（宿泊型）、デイケア（日帰り型）、アウトリーチ（訪問型）の3つの形態があり、心身の健康や育児に不安があり家族からの支援を受けにくい方が対象となる可能性があります。対象月齢・利用料・利用回数などの詳細は世田谷区公式ページでご確認ください。', '出産後のお母さんと赤ちゃんが、助産師から授乳や育児のサポート・相談を受けられる世田谷区の事業です。宿泊して休める「ショートステイ」、日帰りで利用する「デイケア」、自宅に助産師が来てくれる「アウトリーチ（訪問）」の3種類があります。料金や利用できる回数・赤ちゃんの月齢の条件は、世田谷区の公式ページでご確認ください。', 'service', '世田谷区内に住所があり、出産後で心身の健康や育児に不安があり、家族などからの支援を受けにくい母子が対象となる可能性があります。公式情報では、ショートステイ・デイケアは出産後4か月未満、アウトリーチ（訪問型）は出産後1年未満が対象とされています。対象となるかは世田谷区公式で確認してください。', '公式ページ記載（課税世帯の例・確認日時点）：ショートステイ 1泊2日9,000円、以後1日4,500円／デイケア 1回3,000円／アウトリーチ 1回2,000円（いずれも多胎児加算あり）。住民税非課税世帯・生活保護世帯などには減免制度があるとされています。金額・減免・クーポンの扱いは改定され得るため公式で確認してください。', '明確な締切の記載は確認できませんでした。利用登録は妊娠28週から可能とされています。詳細は公式でご確認ください。', '妊娠28週から世田谷区公式LINEで利用登録の申請を行い、出産後に同LINE（電話対応も可）で利用を申し込む方法が公式ページに案内されています。詳細・最新の手続きは世田谷区公式ページでご確認ください。', '非課税世帯等で世田谷区側で課税状況を確認できない場合は、世帯員全員分の課税（非課税）証明書等のアップロードが必要となる場合があると案内されています。必要書類の詳細は公式でご確認ください。', TRUE, '世田谷区 子ども・若者部 児童相談支援課', '03-6304-7731', 'https://www.city.setagaya.lg.jp/03648/1213.html', 'https://www.city.setagaya.lg.jp/03648/1213.html', '【産後ケア事業】産後のお母さんを応援します - 世田谷区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は確認日（2026-06-24）時点で世田谷区公式ページに基づき作成した概況です。対象・利用料・回数・月齢・利用施設は変更される場合があります。最終的な可否・条件は必ず世田谷区公式ページおよび問い合わせ先でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
