insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-postpartum-care', '渋谷区 産後ケア事業', '渋谷区が母子保健法に基づき実施する産後ケア事業。出産後、体調不良や育児不安があり家族などから十分な支援を受けられない母子を対象に、宿泊型・訪問（アウトリーチ）型・デイサービス（通所）型で、母体ケア・乳房ケア・授乳/沐浴指導・育児相談などを提供する可能性があります。対象や利用料・回数・利用施設は渋谷区独自に定められており、利用前に必ず渋谷区公式ページで確認してください。', '渋谷区にお住まいで、出産後の体調や育児への不安があり、家族などのサポートが十分に受けられない方が、助産師などから母体・赤ちゃんのケアや授乳・育児の相談を受けられる仕組みです。施設に泊まる「宿泊型」、自宅に来てもらう「訪問型」、日帰りで施設に通う「デイサービス型」があります。利用できる対象月齢・回数・料金は渋谷区が定めており、申請時期も決まっているため、公式ページでご確認ください。', 'service', '渋谷区内在住の産婦とその子で、体調不良や育児不安があり家族などから十分な支援を受けられない方が対象となる可能性があります。公式ページの記載では、宿泊型は産後5か月未満、訪問型・デイサービス型は産後1年未満が対象とされています。詳細な対象要件は渋谷区公式で確認してください。', '公式ページの記載では、宿泊型は1泊2日7,000円（1日増ごとに3,500円加算）、訪問型は1回1,000円、デイサービス型は1回2,000円とされ、生活保護世帯は免除制度があるとされています。料金・自己負担は変更される可能性があるため、利用前に渋谷区公式で確認してください。', '公式ページの記載では、妊娠28週から利用希望日の14日前まで受け付けるとされています。', '公式ページによると、LINE・郵送・窓口で申請を受け付けています。申請書（産後ケア事業利用申請書）を提出する方式とされています。最新の申請方法・様式は渋谷区公式で確認してください。', '公式ページでは産後ケア事業利用申請書（PDF様式）が案内されています。その他の添付書類の要否は公式で確認してください。', TRUE, '渋谷区 中央保健相談所 母子保健係', '03-3463-1211', 'https://www.city.shibuya.tokyo.jp/kodomo/ninshin/ninshin-sodan/sango_care.html', 'https://www.city.shibuya.tokyo.jp/kodomo/ninshin/ninshin-sodan/sango_care.html', '産後ケア事業 | 妊娠・出産に関する相談・学級 | 渋谷区ポータル', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText', 'contactPhone']::text[], '本情報は渋谷区公式ページをもとにした概要です。当サイトは申請の代行や受給の保証を行いません。対象可否・利用料・利用回数・対象月齢・利用施設・申請方法は変更されることがあるため、利用前に必ず渋谷区公式ページおよび中央保健相談所母子保健係でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
