insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-postpartum-care', '中野区産後ケア事業（ショートステイ・デイケア・アウトリーチ）', '中野区が実施する産後ケア事業。出産後の母子の心身ケアと育児不安の軽減を目的に、ショートステイ（宿泊）・デイケア（日帰り）・アウトリーチ（助産師訪問）の3種類のサービスを提供しています。対象や利用料・利用回数・対象月齢・利用施設はサービス種別や年度改定により異なるため、最新の内容は必ず中野区公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが安心して過ごせるよう、中野区が行っている支援です。助産師さんがいる施設に泊まる「ショートステイ」、日帰りで利用する「デイケア」、自宅に来てもらう「アウトリーチ（訪問）」の3つがあります。利用するには、まずすこやか福祉センターで面接（かんがるー面接）を受けて利用の計画を作ります。料金や利用できる回数・時期はサービスによって違うので、くわしくは中野区の公式ページで確認してください。', 'service', '中野区に住所があり、産後に心身の不調や育児不安があるなどの母子が対象となる可能性があります。公式ページでは、利用には「かんがるープラン」の作成が必要で、ショートステイは出産後満5か月になる前日までと案内されています。対象月齢・条件はサービス種別により異なるため、必ず中野区公式で確認してください。', 'サービス種別ごとに利用料・自己負担額が定められています。公式ページではショートステイの利用料は1回3,000円（1泊2日は6,000円）と記載され、生活保護世帯・住民税非課税世帯は無料とされています。デイケア・アウトリーチの料金や年度改定後の額は種別・時期により異なるため、最新額は公式で確認してください。', '申込期限はサービス種別や対象月齢の範囲で異なります。ショートステイは出産後満5か月になる前日までと案内されています。詳細は公式で確認してください。', '利用にあたっては、まず「かんがるー面接」を受けて「かんがるープラン」を作成する必要があると案内されています。お住まいの地域を担当するすこやか福祉センターへ予約のうえ面接を受け、その後に利用施設へ予約する流れと公式ページに記載されています。詳しい手順は中野区公式で確認してください。', '必要書類は公式ページ・すこやか福祉センターでの案内に従ってください（かんがるープランの作成が前提とされています）。', FALSE, '中野区 地域支えあい推進部 地域包括ケア推進課（各すこやか福祉センター）', NULL, NULL, 'https://www.city.tokyo-nakano.lg.jp/kosodate/kosodatesite_ohirune/nenreibetsu/syussan/sangoshien/sangocare.html', '中野区産後ケア事業【ショートステイ（宿泊）・デイケア（日帰り）・アウトリーチ(助産師訪問）】 | 中野区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText', 'contactPhone', 'contactUrl']::text[], '本内容は中野区公式ページをもとにした概要です。対象条件・利用料・回数・対象月齢・利用施設は変更される場合があるため、利用前に必ず中野区公式ページおよびすこやか福祉センターで最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
