insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-postpartum-care', '杉並区 産後ケア事業', '杉並区が母子保健法に基づき実施する産後ケア事業。区内在住で産後7か月未満の母子を対象に、助産師等による母体ケア・授乳や育児の相談・支援を、宿泊型・日帰り型（個別）・日帰り型（少人数）の形で提供します。区と委託契約をした医療機関や助産院等で実施され、利用には事前申請が必要です。対象月齢・利用料・自己負担・利用回数・利用施設はサービス形態や世帯状況により異なるため、必ず杉並区の公式案内で最新情報をご確認ください。', '出産のあと、心や体の回復、授乳や赤ちゃんのお世話のことで不安なときに、杉並区が助産師さんなどによるケアや相談を受けられるようにする仕組みです。宿泊して受ける形、日帰りで受ける形（個別・少人数）があります。区内に住んでいて産後7か月未満の方が対象になる可能性があり、使うには事前の申し込みが必要です。料金は世帯の状況やサービスの種類で変わるので、公式ページでご確認ください。', 'service', '杉並区内在住で、産後7か月未満の母子が対象となる可能性があります（公式で確認）。利用できる対象月齢はサービス形態や実施施設により異なる場合があるため、最新の杉並区公式案内でご確認ください。', 'サービス（現物給付）。利用料は一部自己負担あり。住民税課税世帯の例として宿泊型1泊2日7,000円（以降1日ごとに3,500円）、日帰り型（個別）1日2,000円、日帰り型（少人数）1日1,000円。非課税世帯は半額、生活保護受給世帯は無料とされています。多胎児加算あり。杉並子育て応援券での支払いも可能とされています（利用できない施設もあり）。金額・自己負担は変更される可能性があるため公式で確認してください。', '公式案内では、申請受付は妊娠8カ月以降から利用予定日の2週間前までとされています（要公式確認）。', '利用には事前の利用申請が必要です。公式案内によると、インターネット電子申請、郵送（杉並区子ども家庭部地域子育て支援課母子保健係宛）、または窓口（同課・保健所/保健センター・子どもセンター）で申請できるとされています。申請受付期間は妊娠8カ月以降から利用予定日の2週間前までとされています。詳細・最新の手続きは公式ページでご確認ください。', '公式案内によると、利用申請書・利用アンケートのほか、非課税世帯は世帯全員の非課税証明書（一定条件で省略可）、生活保護世帯は生活保護受給証明書が必要とされています。必要書類は変更される可能性があるため公式でご確認ください。', TRUE, '杉並区 子ども家庭部 地域子育て支援課 母子保健係', '03-5307-0787', 'https://www.city.suginami.tokyo.jp/s054/1123.html', 'https://www.city.suginami.tokyo.jp/s054/1123.html', '産後ケア事業｜杉並区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは杉並区公式情報をもとにした概要です。対象・利用料・自己負担・利用回数・対象月齢・利用施設は変更される場合があり、サービス形態や世帯状況により異なります。実際の利用可否や手続きは必ず杉並区の公式案内・問い合わせ窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
