insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-postpartum-care', '豊島区 産後ケア事業', '豊島区が母子保健法に基づき実施する産後ケア事業。産後のお母さんの心身のケアや授乳・育児の相談支援を受けられるよう、宿泊型・通所(デイ)型・訪問(アウトリーチ)型の3つの形態でサポートする事業です。豊島区公式ホームページで案内されています。', '出産後、お母さんの体と心を休めたり、授乳や育児の相談をしたい方のための豊島区の事業です。施設に泊まる「宿泊型」、施設に通う「通所型」、自宅に来てもらう「訪問型」の3つから選べます。妊娠28週以降に申し込めます。利用料や回数の上限は形態ごとに決まっており、住民税非課税世帯などは無料になる場合があります。くわしくは豊島区の公式ページをご確認ください。', 'service', '申込・利用時に豊島区に住民登録があり、産後ケアを必要とするお母さんと赤ちゃんが対象となる可能性があります。公式の案内では、宿泊型・通所型はおおむね生後4か月未満、訪問型はおおむね生後1歳未満の赤ちゃんとお母さんが対象とされています。詳しい対象要件は豊島区公式ページで確認してください。', '利用料(自己負担額)はサービスの形態により異なります。公式の案内では、宿泊型1日2,500円・通所型1回1,500円・訪問型1回1,000円とされ、住民税非課税世帯・生活保護世帯は無料、多胎児は加算があるとされています。金額や回数の上限・対象月齢は区の制度として変更される場合があるため、必ず豊島区公式ページで最新の内容を確認してください。', '公式の案内では妊娠28週以降に申込みが可能とされています。利用券の発送に通常2週間程度かかるとされるため、利用を希望する場合は早めの申込みが案内されています。詳細は豊島区公式ページで確認してください。', '妊娠28週以降に、電子申込・窓口申込・郵送申込のいずれかで申請できるとされています。承認された場合、通常2週間程度で利用承認通知書兼利用券が郵送されると公式で案内されています。申請方法・必要書類の詳細は豊島区公式ページで確認してください。', '必要書類は申請方法(電子・窓口・郵送)により異なる場合があります。詳細は豊島区公式ページで確認してください。', TRUE, '豊島区 健康推進課 / 長崎健康相談所', '03-6311-6842(健康推進課) / 03-3957-1191(長崎健康相談所)', NULL, 'https://www.city.toshima.lg.jp/565/kenko/kenko/1804131444.html', '産後ケア事業 - 豊島区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は豊島区公式ページ(2026-06-12更新、2026-06-24確認)に基づく概要です。利用料・自己負担額・利用回数・対象月齢・利用施設など区ごとに異なる詳細や最新の変更は、必ず豊島区公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
