insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot postpartum-care import', '{"slug":"tokyo-toshima-postpartum-care","status":"published","title":"豊島区 産後ケア事業","officialUrl":"https://www.city.toshima.lg.jp/565/kenko/kenko/1804131444.html","topic":"postpartum-care"}'::jsonb, 'pilot:tokyo-toshima-postpartum-care:dG9reW8tdG9zaGltYS1wb3N0cGFydHVtLWNhcmV8' from public.support_programs sp where sp.slug='tokyo-toshima-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-postpartum-care', '産後ケア事業（東京都北区）', '東京都北区が母子保健法に基づき実施する産後ケア事業。出産後の母子の心身のケアや育児相談を、宿泊型（産後ショートステイ）・日帰り型（産後デイケア）・訪問型（産後アウトリーチ）の3つの形で提供します。1度の申請で3つの型すべてを利用できる可能性があります。対象や利用料・利用回数・対象月齢・利用できる施設は公式ページでの確認が必要です。', '出産のあと、お母さんの体を休めたり、赤ちゃんのお世話や授乳の相談ができる北区の支援です。助産院などに泊まる宿泊型、日中に通う日帰り型、自宅に来てもらう訪問型の3種類があります。利用したい場合は妊娠中（8か月・28週以降）に事前申請が必要になる可能性があります。詳しい対象・料金・利用できる施設は北区の公式ページでご確認ください。', 'service', '北区に住民登録がある産後のお母さんと赤ちゃんが対象となる可能性があります（公式記載では医療行為が必要な方は対象外）。対象となる産後の月齢は型により異なり（宿泊型は産後4か月未満、日帰り型は産後6か月未満、訪問型は産後1年以内など）、最新の対象条件は公式で確認してください。', '現物サービス（産後の母子ケア）。利用料の一例として、公式で宿泊型1日3,300円・日帰り型1日2,500円・訪問型1回1,000円と案内されています（多胎児加算あり）。住民税非課税世帯・生活保護世帯は自己負担が免除される旨が公式に記載されています。金額・自己負担は変更される場合があり、施設により追加料金が生じる場合があるため公式での確認が必要です。', '妊娠8か月（28週）以降に事前申請するよう公式で案内されています。利用前の事前申請が必要となる可能性があるため、早めに公式ページや問い合わせ先で確認してください。', '妊娠8か月（28週）以降に事前申請する旨が公式に案内されています。令和7年10月以降はmila-e認証を用いた電子申請フォームでの申請となり、電子申請が難しい方は紙でも受け付けると記載されています。事前申請からクーポン発行完了まで10営業日程度かかる場合があります。申請方法の詳細・最新情報は公式ページでご確認ください。', '利用時にはクーポンを表示できる電子機器または利用承認通知書、母子健康手帳が必要と案内されています。住民税非課税世帯として自己負担免除を受ける場合は世帯全員の非課税証明書が必要となる場合があります。必要書類は申請時期等により異なるため公式で確認してください。', TRUE, '東京都北区 健康部 保健サービス課 保健サービス係', '03-3908-7050', 'https://www.city.kita.lg.jp/children-edu/pregnancy/1018244/1002787.html', 'https://www.city.kita.lg.jp/children-edu/pregnancy/1018244/1002787.html', '産後ケア事業｜東京都北区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは北区公式情報をもとにした概要です。対象・利用料・自己負担・利用回数・対象月齢・利用できる施設・申請方法は変更される場合があり、内容により利用できない場合もあります。利用の可否や最新の詳細は必ず北区の公式ページまたは問い合わせ先でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
