insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-postpartum-care', '荒川区 産後ケア事業', '荒川区が母子保健法に基づき実施する産後ケア事業。出産後の母子の心身のケアや授乳・育児の相談・支援を、宿泊型・日帰り（デイサービス）型・訪問（アウトリーチ）型の3つの形で受けられる可能性があります。対象や利用料・回数・利用できる施設は公式サイトで確認してください。', '出産のあと、赤ちゃんとお母さんの体や心を休めたり、授乳・育児の相談をしたりできる荒川区のサービスです。施設に泊まる「宿泊型」、日帰りで利用する「日帰り型」、助産師さんが自宅に来てくれる「訪問型」があります。荒川区に住んでいて出産後1年以内の方が対象になる可能性があります。利用料の一部を区が負担しますが、自己負担が生じる場合があります。申し込みや料金などのくわしいことは荒川区の公式サイトで確認してください。', 'service', '荒川区に住所があり、出産後おおむね1年以内のお母さんと赤ちゃんが対象となる可能性があります。家族などから十分な支援が受けられない場合や、産後の心身のケア・育児相談を希望する方が利用できる可能性があるとされていますが、具体的な対象は公式サイトで確認してください。', '宿泊型・日帰り（デイサービス）型・訪問（アウトリーチ）型のサービスを利用できる可能性があります。利用には施設利用料から区の負担額を差し引いた自己負担が生じる場合があり、生活保護世帯は全額免除となる場合があります。利用回数・日数（例として宿泊型は数泊まで、日帰り型・訪問型は複数回まで）や金額は年度・施設により異なるため、最新の内容は公式サイトで確認してください。', '通年で申請を受け付けているとされますが、利用決定まで時間がかかる場合があります。最新の受付状況は公式サイトで確認してください。', '電子申請（Logoフォーム）のほか、区役所2階の窓口申請、郵送申請で利用登録の申請ができるとされています。利用決定まで2週間程度かかる場合があり、妊娠中（おおむね妊娠7か月以降）から申し込める場合があります。詳細・最新の手続きは公式サイトで確認してください。', '利用登録申請にあたって必要な書類は公式サイト・実施要綱で確認してください。', TRUE, '荒川区 子ども家庭部 子ども・若者課 子育て事業係', '03-3802-3111', 'https://www.city.arakawa.tokyo.jp/a035/ninshinshussan/ninsampushien/sangokea_reiwa7.html', 'https://www.city.arakawa.tokyo.jp/a035/ninshinshussan/ninsampushien/sangokea_reiwa7.html', '荒川区産後ケア事業／荒川区公式サイト', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText', 'targetPeople']::text[], '利用料・自己負担額・利用回数・対象月齢・利用できる施設は年度や施設により異なる場合があります。最新かつ正確な情報は必ず荒川区の公式サイトでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
