insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-postpartum-care', '板橋区 産後ケア事業', '板橋区が母子保健法に基づき実施する産後ケア事業です。出産後の母子の心身のケアや育児の相談・支援を、宿泊型・通所（デイ）型・訪問（アウトリーチ）型の3つの形で受けられる可能性があります。助産師による授乳相談・育児支援などを通じて、安心して子育てができるようサポートする事業です。対象者・利用料・自己負担額・利用回数・対象月齢・利用施設は公式ページでご確認ください。', '板橋区にお住まいで赤ちゃんを出産した方が、産後の体や心のケア・育児の相談を受けられる事業です。宿泊して受ける宿泊型、施設に通って受ける通所（デイ）型、助産師が自宅を訪問する訪問型の3つがあります。利用には妊娠8か月以降の事前の利用登録申請が必要とされています。利用料や利用できる回数、対象となる時期は公式ページでご確認ください。', 'service', '事業利用日に板橋区に住民登録があるお母さんと赤ちゃんが対象となる可能性があります（感染性疾患や入院加療が必要な場合は利用できないとされています）。対象となる産後の期間は類型ごとに異なり、公式では宿泊型は産後120日以内、通所型は産後6か月以内、訪問型は産後1年以内とされています。具体的な対象要件は板橋区の公式ページでご確認ください。', '公式ページでは、宿泊型は1泊2日8,000円・1日追加4,000円、通所型は1回2,000円、訪問型は1回600円（すくすくカード利用時は2回まで無料）と案内されています。非課税世帯・生活保護受給世帯は費用負担が免除、多胎の場合は2人目以降の料金が免除とされています。利用回数の上限は宿泊型6泊7日まで・通所型7回まで・訪問型5回までと案内されています。金額・回数は改定される可能性があるため公式ページでご確認ください。', '通年（妊娠8か月以降に利用登録申請。利用は類型ごとの産後の期間内）。最新の取扱いは公式ページでご確認ください。', '妊娠8か月以降に産後ケア事業の利用登録申請を行う流れとされています。申請方法はWeb申請・窓口申請・郵送申請があると案内されています。詳細・最新の手続きは公式ページでご確認ください。', '産後ケア事業利用登録申請書。世帯状況の変更がある場合は住民税非課税証明書（公式ページで確認）。', TRUE, '板橋区 健康生きがい部 健康推進課 母子保健係', '03-3579-2313', 'https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1051233.html', 'https://www.city.itabashi.tokyo.jp/kosodate/ninshin/ninshin/1051233.html', '産後ケア事業｜板橋区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは板橋区公式サイトの情報をもとにした概要です。利用料・自己負担額・利用回数・対象月齢・利用施設・申請手続きは変更される場合があるため、必ず板橋区公式ページで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
