insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-postpartum-care', '練馬区 産後ケア事業', '練馬区が実施する産後ケア事業です。助産師のいる施設での母子ショートステイ（宿泊）、母子デイケア（日帰り）、産後ケア訪問（助産師による家庭訪問）を通じて、出産後のお母さんと赤ちゃんが育児相談や授乳相談などのケアを受けられる事業として公式ページで案内されています。対象や利用料・利用回数などの詳細は公式サイトで確認できます。', '出産後のお母さんと赤ちゃんが、助産師のいる施設に泊まったり（ショートステイ）、日帰りで通ったり（デイケア）、自宅に助産師が来てくれたり（訪問）して、育児や授乳の相談・ケアを受けられる練馬区の事業です。利用には事前の申請（電子申請）が必要で、所得に応じて自己負担額が変わる可能性があります。', 'service', '練馬区民で、産後ケアを必要とする出産後1年未満の母子（母子ショートステイは概ね生後4か月まで）が対象となる可能性があります。母子ともに医療的な処置が不要であることなどの条件が公式ページに記載されています。詳細・最新の対象要件は公式で確認してください。', 'サービス利用に対し自己負担あり（公式で確認）。公式ページ記載では、母子ショートステイは1泊2日7,000円・以降1日3,500円、母子デイケアは1日1,500円、産後ケア訪問は1回500円とされ、住民税非課税世帯・生活保護世帯は無償とされています。金額・区分は改定の可能性があるため最新は公式で要確認。', '公式ページに明確な申請期限の記載は確認できませんでした。利用には事前の登録・申請が必要とされています。最新は公式で確認してください。', '公式ページの案内では、LoGoフォームによる電子申請が示されています。妊婦面談を通じて利用者カードの交付または電子クーポンの登録を受けたうえで利用する流れとされています（令和8年4月1日以降は妊婦面談で電子クーポンを交付、それ以前は紙の利用者カード）。詳細手順は公式ページで確認してください。', '公式ページでは、利用者カードの交付または電子クーポンの登録が利用の前提とされています。具体的な必要書類は公式ページ・申請フォームで確認してください。', TRUE, '練馬区 健康部 健康推進課 母子保健係', '03-5984-4621', 'https://www.city.nerima.tokyo.jp/hokenfukushi/hoken/sukoyaka/sango-keajigyou.html', 'https://www.city.nerima.tokyo.jp/hokenfukushi/hoken/sukoyaka/sango-keajigyou.html', '産後ケア事業：練馬区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は2026-06-24時点で練馬区公式ページを確認して作成した概括です。利用料・自己負担額・利用回数・対象月齢・利用施設などは変更される可能性があり、申請の可否や利用条件を保証するものではありません。必ず練馬区公式ページおよび担当窓口で最新の内容をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
