insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-postpartum-care', '足立区 産後ケア事業', '足立区が母子保健法に基づき実施する産後ケア事業。出産後の母子の心身のケアや育児支援のため、宿泊型・日帰り（デイサービス）型・訪問（アウトリーチ）型のサービスを提供します。足立区に住民登録があり、産後一定期間内のお母さんと赤ちゃんが対象となる可能性があります。利用料・自己負担・利用回数・対象月齢・利用施設は公式ページで確認してください。', '出産のあと、足立区に住んでいるお母さんと赤ちゃんが、心と体を休めたり育児の相談や手助けを受けたりできる制度です。施設に泊まる「宿泊型」、日中だけ通う「日帰り（デイサービス）型」、助産師などが家に来てくれる「訪問型」があります。対象になる産後の期間や利用料、利用できる回数・施設は区が決めており、住民税非課税世帯などは利用料が免除されることもあります。申請は妊娠中（妊娠28週以降）からでき、オンラインや窓口で受け付けています。くわしくは足立区の公式ページで確認してください。', 'service', '足立区に住民登録があり、産後一定期間内（公式によると、宿泊型・日帰り型は産後4か月未満、訪問型・デイサービス型は産後1年未満）で産後ケアを必要とするお母さんと赤ちゃんが対象となる可能性があります。詳しい対象要件は足立区公式ページで確認してください。', '公式によると、自己負担額の目安はデイサービス型500円、宿泊型1日2,500円（多胎児は2人目以降1日1,000円追加）、日帰り型1日1,250円、訪問型1回1,000円。住民税非課税世帯・生活保護世帯には免除制度があります。利用料・自己負担は改定されることがあるため最新は公式で確認してください。', '公式によると、利用希望日の2週間前まで（申請は妊娠28週以降から可能）。', '公式によると、オンライン申請または窓口申請。妊娠28週（妊娠8か月）以降から利用希望日の2週間前までに申請します。具体的な申請手順・窓口は足立区公式ページで確認してください。', '公式によると、母子健康手帳、利用承認通知書、（減免を希望する場合）住民税非課税証明書など。詳細は公式ページで確認してください。', TRUE, '足立区 衛生部 保健予防課 保健予防係', '03-3880-5892', 'https://www.city.adachi.tokyo.jp/hoken/fukushi-kenko/kenko/sangokea.html', 'https://www.city.adachi.tokyo.jp/hoken/fukushi-kenko/kenko/sangokea.html', '産後ケア｜足立区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本内容は足立区公式ページの情報をもとにした概要です。対象要件・利用料・自己負担・利用回数・対象月齢・利用施設・申請方法は変更される場合があるため、利用前に必ず足立区公式ページおよび保健予防課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
