insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'katsushika'), 'tokyo-katsushika-postpartum-care', '葛飾区 産後ケア事業', '葛飾区が母子保健法に基づき実施する産後ケア事業。区内に住民票のある産後の母子を対象に、宿泊型・通所（デイ）型・訪問（アウトリーチ）型のいずれかで、母体の休養や赤ちゃんのケア、授乳・育児に関する相談・支援を区指定の医療機関・助産院で受けられる可能性があります。対象・利用料・回数・対象月齢・利用施設は年度や類型により異なるため、必ず公式ページでご確認ください。', '出産後のお母さんと赤ちゃんが、区の指定する病院・助産院などで、お母さんの休養や赤ちゃんのお世話、授乳・育児の相談を受けられる葛飾区の支援です。宿泊して受ける「宿泊型」、施設に通う「通所（デイ）型」、助産師が自宅に来る「訪問型」から選べる可能性があります。対象や料金、回数は年度によって変わることがあるので、申し込み前に区の公式ページで最新の内容を確認してください。', 'service', '葛飾区に住民票のある産後1年未満の母子が対象となる可能性があります（公式では産後1年未満と案内。流産・死産を経験された方も対象とされ、宿泊型は産後4か月未満が対象との記載がある一方、早産の場合は期間延長の相談ができるとされています）。対象範囲・月齢の詳細は公式でご確認ください。', '公式（令和8年度）では基本利用料を無料と案内し、宿泊型の差額ベッド代について1日あたり1万円を上限に補助するとの記載があります。オプションは別途費用となる場合があります。ただし利用料・自己負担は年度・類型・施設により異なるため、最新の金額は公式ページでご確認ください。', '公式ページに明確な申請期限の記載は確認できませんでした。郵送申請は手続きに1か月ほどかかるとされ、早めの申請が推奨されています。', '公式案内によると、(1) ゆりかご面接時または保健センター窓口で申込み、(2) 出産後に希望するケアの実施施設へ予約、(3) 利用時に「産後ケア利用回数確認票」と親子（母子）健康手帳を持参、という流れとされています。郵送申請も可能で、手続きに1か月ほどかかる場合があるため早めの申請が案内されています。詳細・最新の手順は公式ページでご確認ください。', '親子健康手帳（母子健康手帳）、官公署発行の写真付き本人確認資料1点。代理人が申請する場合は委任状も必要とされています。', FALSE, '青戸保健センター 保健サービス係', '03-3602-1284', 'https://www.city.katsushika.lg.jp/kenkou/1000050/1001803/1030308/index.html', 'https://www.city.katsushika.lg.jp/kenkou/1000050/1001803/1030308/1020863.html', '令和8年度 産後ケア事業｜葛飾区公式サイト', '2026-06-24', 'high', ARRAY['targetPeople', '対象月齢（宿泊型/通所型/訪問型ごとの上限）', '利用施設の一覧']::text[], '本情報は葛飾区公式サイト（確認日2026-06-24）に基づく概要です。対象・利用料・自己負担・利用回数・対象月齢・利用施設は年度や類型により異なり、変更される場合があります。必ず公式ページおよび保健センターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
