insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-postpartum-care', '江戸川区 産後ケア事業', '江戸川区が母子保健法に基づき実施する産後ケア事業。出産後のお母さんと赤ちゃんが、助産師などから心身のケアや授乳・育児の相談・支援を受けられる制度で、宿泊型・デイサービス（通所）型・訪問型の3つの形態が用意されています。区内に住民登録がある産後の母子が対象となる可能性があり、利用料・自己負担額・利用できる回数や日数・対象となる月齢・利用できる施設は、形態や施設ごとに異なります。詳細・最新の内容は必ず江戸川区公式サイトでご確認ください。', '出産のあと、体やこころを休めたり、赤ちゃんのお世話や授乳について助産師さんに相談したりできる江戸川区の支援です。区内に住んでいる産後のお母さんと赤ちゃんが対象となる場合があります。利用のしかたは「泊まって受ける(宿泊型)」「日帰りで受ける(デイサービス型)」「自宅に来てもらう(訪問型)」の3つがあり、料金や使える回数・日数、赤ちゃんの月齢、使える施設は形態や施設によって違います。妊娠28週ごろから申し込めます。くわしいことや最新の内容は、江戸川区の公式ホームページで確認してください。', 'service', '江戸川区に住民登録がある産後の母子が対象となる可能性があります（公式によると宿泊型・デイサービス型は産後4か月未満、訪問型は産後1年未満。流産・死産から1年未満の方も対象となる場合があります）。感染症がなく医療行為が不要な方に限られるとされています。対象・要件は形態ごとに異なるため、公式で確認してください。', 'サービス（産後の母子への心身のケア・育児相談等）。利用料は形態により異なり、公式によるとデイサービス型は1回3,000円、宿泊型は1泊2日7,000円（1日増ごとに3,500円加算）、訪問型は1回2,000円。多胎児分は無料、住民税非課税世帯・生活保護世帯は全額免除とされています（確認日時点）。詳細・最新の金額は公式サイトでご確認ください。', '公式によると妊娠28週から申請可能とされています。詳細は公式サイトでご確認ください。', '公式によると、妊娠28週から電子申請または郵送で利用申請を行い、承認番号を取得したうえで各施設に予約する流れとされています（訪問型は運営事業者の申込フォームまたは電話受付）。申込時期・方法の詳細は公式サイトでご確認ください。', '必要書類は公式サイト記載の利用申請手続きをご確認ください（確認日時点で本文に明確な一覧の記載は確認できませんでした）。', TRUE, '江戸川区 健康部健康サービス課 母子保健係', '03-5661-2466', 'https://www.city.edogawa.tokyo.jp/kosodate/ninshin/sangokea/index.html', 'https://www.city.edogawa.tokyo.jp/kosodate/ninshin/sangokea/index.html', '産後ケア 江戸川区ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は確認日(2026-06-24)時点の江戸川区公式サイトの内容に基づく概要です。利用料・自己負担・利用回数や日数・対象月齢・実施施設は形態や施設ごとに異なり、変更される場合があります。最新かつ正確な内容は必ず江戸川区公式サイト・担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
