insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/sango.html', 'WebFetchでprogram.officialUrl（https://www.city.chiyoda.lg.jp/koho/kosodate/kosodate/ninshin/sango.html）を再取得し検証（検証日2026-06-24）。(a)到達：ページ到達・更新日2026年6月1日。(b)許可ホスト：www.city.chiyoda.lg.jp＝.lg.jp かつ city.* パターンで許可ホスト一致（FAQ専用ドメインではない）。(c)当該区事業：千代田区が実施する産後ケア事業（宿泊型・通所型・訪問型）の公式ページであることを本文「出産後のお母さんが安心して子育てできるように、助産師や看護師が産後の心身のケアや育児をサポートします」で確認。(d)現行：受付終了・古い年度向けの表記なし。令和8年4月1日以降出産者向けの回数体系（訪問型5回/通所型5回/宿泊型6泊7日）を反映。「令和8年3月31日までに出産された方はこれまでどおり3回」「とりこえ助産院との契約終了」は施設・経過措置の注記であり、ページ自体の失効ではない。(e)国の制度誤認なし：母子保健法の一般説明や国の' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chuo.lg.jp/a0031/kosodate/shussan/shussanshien/user_fkensu_time_20170323.html', '敵対的検証を実施。program.officialUrl（https://www.city.chuo.lg.jp/a0031/kosodate/shussan/shussanshien/user_fkensu_time_20170323.html）をWebFetchで2回取得し全項目を独立確認した。検証結果: (a)到達=HTTP200で到達可。(b)許可ホスト=www.city.chuo.lg.jp（.lg.jp 公式自治体ドメイン、FAQ専用ドメインでない）に一致。(c)当該区ページ=ページタイトル「産後ケア事業」、中央区が実施する事業ページであることを確認。(d)現行性=掲載日2026-06-22、令和8年4月1日からの変更予定を記載した現行ページ（過去年度・受付終了でない）。(e)国制度誤認なし=母子保健法・国の一般説明ではなく中央区独自実施の事業ページであることを確認。(f)対象の部分を全体化せず=対象月齢が施設により異なる旨を可能性表現で記載。(g)制度混在なし=宿泊型・日帰り型・訪問型は同一産後ケア事業の3類型。(h)区差概括=利用料・回数・対象は概括し「公式・施設一覧で' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.minato.tokyo.jp/chiikihoken/kodomo/boshi-shortstay.html', '敵対的検証：program.officialUrl(boshi-shortstay.html)および連動ページ(boshi-nyuboucare.html)をWebFetchで再取得し検証(2026-06-24)。(a)両ページとも正常到達(404・受付終了でない)。宿泊型は最終更新2026-04-01、デイ・乳房ケアは2026-06-15(ページID133041)で現行年度。(b)ホストはwww.city.minato.tokyo.jpで.tokyo.jp許可ホスト、FAQ専用ドメインでない。(c)(e)実施主体は港区(みなと保健所健康推進課地域保健係)で、母子保健法の一般説明や国制度紹介でなく港区独自実施の産後ケア事業ページと確認。(g)宿泊型/通所型(デイ)/訪問型(乳房ケア)は同一産後ケア事業の類型であり複数制度の混在でない。(f)対象・料金は施設差を概括し「公式で確認」を付記。(h)断定回避・区差概括ともに適合。1点是正：宿泊型の対象月齢を一次調査では『産後4〜10週未満』としていたが、公式ページ現行記載では『施設により産後10週未満〜産後5か月未満』の範囲であり、targe' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='minato' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
