insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.bunkyo.lg.jp/b029/p001557.html', '敵対的検証を実施（検証日2026-06-24）。program.officialUrl（https://www.city.bunkyo.lg.jp/b029/p001557.html）をWebFetchで再取得し、以下を確認した。(a)到達=正常（404・エラーなし）。(b)許可ホスト=city.bunkyo.lg.jp（.lg.jp）で合致、FAQ専用ドメインではない。(c)文京区が実施する産後ケア事業の当該区ページであることを確認（事業名「宿泊型ショートステイ・デイサービス型サロン（個別）」、対象「文京区に住民登録がある出産後のお母さんと赤ちゃん」）。(d)古い年度・受付終了・募集締切の記載なし（最終更新2026-06-09表示）。(e)母子保健法の一般説明や国の制度紹介ではなく、文京区独自実施の事業ページであることを確認。(f)対象の一部を全体として断定していない（住民登録・月齢条件はuncertainFieldsで概括）。(g)宿泊型・デイサービス型・訪問型は同一の産後ケア事業の類型であり混在ではない。(h)区差・施設差のある利用料/回数/対象月齢は概括し「公式で確認」を付記、' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='bunkyo' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
