insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.koto.lg.jp/260501/kodomo/ninshinshussan/kenko/99710.html', '江東区公式（city.koto.lg.jp／.lg.jp許可ホスト）でWebFetch再検証済み・ok=true。トップ/99710（更新日2026-04-01・令和8年度運用）が江東区自身の産後ケア事業（母子保健法に基づく区の独自実施事業であり国制度の一般説明ではない）であることを確認。宿泊型/99711で利用料（1泊2日9,800円〜5泊6日29,400円、多胎1人1日2,400円加算、住民税非課税・生活保護世帯は減免、施設により受入月齢制限）と申込（ゆりかご面接→承認番号→施設へ電話/HP予約）を確認。スポット型・訪問型/99713は対象が産後1年未満（宿泊・日帰りは産後4か月未満）と確認し、一次調査の「乳房ケアは産後1年未満」表現を訪問・スポット型自体の対象期間として是正。受付終了の記載なし・現行。利用料/対象月齢/回数/施設は類型・施設により差があるためdisclaimer＋uncertainFieldsで概括し「公式で確認」を明記。許可ホスト一致・当該区の産後ケア事業・非断定・現行のためok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='koto' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
