insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shibuya.tokyo.jp/kodomo/ninshin/ninshin-sodan/sango_care.html', 'WebFetchで program.officialUrl（https://www.city.shibuya.tokyo.jp/kodomo/ninshin/ninshin-sodan/sango_care.html）を再検証し、一次調査の妥当性を確認した。(a)到達=200で正常表示、404やエラーなし。(b)許可ホスト=www.city.shibuya.tokyo.jp（.tokyo.jp かつ city.* に合致。FAQ専用ドメインではない）。(c)当該区ページ=タイトル「産後ケア事業 | 妊娠・出産に関する相談・学級 | 渋谷区ポータル」で渋谷区の産後ケア事業そのもの。(d)現行=更新日2026年6月1日、2026年4月1日付の最新お知らせあり。受付終了・古い年度ではない。(e)渋谷区独自実施の事業=本文「渋谷区では、…産後ケア事業を行なっています」と明記され、母子保健法の一般説明や国の制度紹介ではない。(f)対象の一部を全体と書いていない=targetPeoneは概括し uncertainFields に列挙、本文は「可能性があります」「公式で確認」で限定。(g)複数制度の' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shibuya' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
