insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.suginami.tokyo.jp/s054/1123.html', '敵対的検証を実施（検証日2026-06-24）。program.officialUrl（https://www.city.suginami.tokyo.jp/s054/1123.html）をWebFetchで再到達確認。(a)到達OK。(b)許可ホスト一致＝www.city.suginami.tokyo.jp（city.*／.tokyo.jp、FAQ専用ドメインではない）。(c)杉並区が実施する「産後ケア事業」そのものの当該区ページであることを確認（ページタイトル「産後ケア事業」、杉並区独自の事業運営要項を記載）。(d)現行＝2026年4月1日更新・令和8年度情報、「受付終了」等の記載なし。(e)国の制度／母子保健法の一般説明ではなく杉並区実施事業として正しく扱っている。(f)対象＝「杉並区内に住所を有する産後7か月未満のお母さんと赤ちゃん」（例：令和8年4月1日生まれは令和8年10月31日まで）で、一部を全体と誤記していない。(g)宿泊型・日帰り型（個別）・日帰り型（少人数）は同一産後ケア事業の類型であり複数制度の混在ではない。(h)変動しうる利用料・対象月齢・回数・施設は概括＋「公' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='suginami' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.toshima.lg.jp/565/kenko/kenko/1804131444.html', '敵対的検証を実施。program.officialUrl (https://www.city.toshima.lg.jp/565/kenko/kenko/1804131444.html) をWebFetchで再取得し、一次調査の全主張を独立確認した(2026-06-24)。検証結果: (a)到達=200で正常取得。(b)許可ホスト=www.city.toshima.lg.jp は .lg.jp かつ city.* パターンに合致しFAQ専用ドメインではない→合格。(c)当該区ページ=豊島区が実施する産後ケア事業の公式案内ページであることを本文で確認。(d)現行性=更新日2026年6月12日、令和8年4月から宿泊型を3泊4日→6泊7日に拡大という前向きな最新情報あり、受付終了・古い年度ではない。(e)母子保健法の一般説明や国の制度紹介の誤認なし=豊島区独自の実施事業として料金・回数・問い合わせ先が具体的に記載。(f)対象の一部を全体と記述していない=宿泊/通所型おおむね生後4か月未満・訪問型おおむね生後1歳未満の区別を正しく記載。(g)複数制度の混在なし=宿泊/通所/訪問は同一産後ケア事' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='toshima' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
