insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.adachi.tokyo.jp/hoken/fukushi-kenko/kenko/sangokea.html', 'WebFetchでprogram.officialUrlを検証。(a)到達:200で正常取得。(b)許可ホスト:www.city.adachi.tokyo.jp（.tokyo.jp/city.*に合致、FAQ専用ドメインではない）。(c)足立区が母子保健法に基づき実施する産後ケア事業そのものの当該区ページであることを確認(衛生部保健予防課保健予防係 所管、電話03-3880-5892)。(d)現行性:ページ更新日2026年4月1日(令和8年4月1日からの変更点が明記)で現行・受付終了でない。(e)国の制度/母子保健法の一般説明ではなく足立区の実施事業ページであることを確認。(f)対象は類型別月齢(デイサービス型・訪問型=産後1年未満、宿泊型・日帰り型=産後4か月未満)を概括しており一部を全体と誤記していない。(g)宿泊型・日帰り型・訪問型・デイサービス型は同一産後ケア事業の類型であり複数制度の混在ではない。(h)断定回避・利用料/回数/対象は概括+「公式で確認」表現あり。一次調査の自己負担額(デイサービス型500円/宿泊型2,500円/日帰り型1,250円/訪問型1,000円)、対象月' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.katsushika.lg.jp/kenkou/1000050/1001803/1030308/1020863.html', '検証（確認日2026-06-24）：program.officialUrl を WebFetch で再取得し全ゲートを点検。(a)到達成功。(b)許可ホスト www.city.katsushika.lg.jp（.lg.jp・city.*）適合。(c)「令和8年度 産後ケア事業」で「葛飾区に住民票のある」「契約施設で…基本利用料を無料とします」と明記、葛飾区独自実施ページと確認。(d)更新日「令和8年6月2日」で現行・受付終了記載なし。(e)母子保健法の一般説明や国制度紹介ではなく区の実施案内（誤認なし）。(f)対象は産後1年未満と総括し月齢制限は留保。(g)宿泊/通所/訪問は同一事業の3類型で混在に非該当。(h)区差ある利用料・回数・対象を概括し「公式で確認」付記、FORBIDDEN・断定なし。今回のライブ取得で『基本利用料 無料／差額ベッド代1万円/日補助』を公式本文で再確認でき、benefitAmount を無料先頭＋留保とする扱いが妥当のためuncertainFieldsから外した。対象・3類型・回数（宿泊7日分割可、通所＋訪問計7回・多胎10回）・問い合わせ（青戸保健センター保' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='katsushika' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.edogawa.tokyo.jp/kosodate/ninshin/sangokea/index.html', '敵対的検証完了（2026-06-24）。program.officialUrl（index）をWebFetchで到達確認。許可ホスト www.city.edogawa.tokyo.jp（city.*）に一致。indexは3形態（宿泊型/デイサービス型/訪問型）のハブで、各事業の実ページURL（/e052/kosodate/ninshin/sangokea/tuusyo.html, houmon.html, shukuhaku.html）を取得し、引用された数値・対象・申請を一次照合した。デイサービス型: 1回3,000円・1出産につき2回まで・産後4か月未満・多胎児無料・非課税/生活保護世帯は全額免除・妊娠28週から電子/郵送申請＝公式と一致。訪問型: 1回2,000円・3回まで・産後1年未満（流産死産1年未満も可）・多胎児無料・非課税/生活保護免除＝公式と一致。デイサービス型ページの更新日は2026-04-01（令和8年4月更新）で現行、受付終了・古い年度の記載なし。母子保健法の一般説明ではなく江戸川区が実施する当該区の事業ページであることを確認。targetPeopleは形態ごとに' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
